&__#{$element}
      @each $modifier in ('xs', 's', 'm', 'l', 'xl', 'none')
        &--#{$modifier}
          @if $modifier == 'xs'
            margin-#{$position}: var(--spacing-xs) !important
          @else if $modifier == 's'
            margin-#{$position}: var(--spacing-sm) !important
          @else if $modifier == 'm'
            margin-#{$position}: var(--spacing-md) !important // 12px -> 16
          @else if $modifier == 'l'
            margin-#{$position}: var(--spacing-lg) !important // 16 -> 24
          @else if $modifier == 'xl'
            margin-#{$position}: var(--spacing-xl) !important // 20 -> 32
          @else if $modifier == 'none'
            margin-#{$position}: 0 !important

&__#{$element}
      @each $modifier in ('xs', 's', 'm', 'l', 'xl', 'none')
        &--#{$modifier}
          @if $modifier == 'xs'
            padding-#{$position}: var(--spacing-xs) !important
          @else if $modifier == 's'
            padding-#{$position}: var(--spacing-sm) !important
          @else if $modifier == 'm'
            padding-#{$position}: var(--spacing-md) !important // 12px -> 16px
          @else if $modifier == 'l'
            padding-#{$position}: var(--spacing-lg) !important // 16px -> 24px
          @else if $modifier == 'xl'
            padding-#{$position}: var(--spacing-xl) !important // 20px -> 32px
          @else if $modifier == 'none'
            padding-#{$position}: 0 !important

&__#{$element}
      @each $modifier in ('xs', 's', 'm', 'l', 'xl', 'hg', 'none')
        &--#{$modifier}
