          @else if $modifier == 'hg'
            padding-#{$position}: $spacing-hg
          @else if $modifier == 'none'
            padding-#{$position}: 0

@if $limit != 0

		@if $delimiter != null
			$length: string.length($string)

			// Return all characters
			@if string.length($delimiter) == 0

				@for $index from 1 through if(sass($limit == null): $length; else: math.min($limit, $length))
					$list: list.append($list, string.slice($string, $index, $index))

				@return $list

			// Split at delimiter
			$index: string.index($string, $delimiter)

			@while $index != null
				$list: list.append($list, string.slice($string, 1, $index - 1))
				$string: string.slice($string, $index + 1)

				@if $limit != null and list.length($list) == $limit
					@return $list

				$index: string.index($string, $delimiter)

		$list: list.append($list, $string)

@if $scale-grid-direction == rtl
        @for $i from 1 through $units
          $grid-return: $grid-return + ms($counter - $columns, 100%)
          // the only difference between rtl and ltr is this
          $counter: $counter + 1
          @if $counter == $columns
            $grid-remainder: 0
            $counter: 0
            @for $j from 1 through $columns
              $grid-remainder: $grid-remainder + ms($counter - $columns, 100%)
              $counter: $counter + 1
          @if $i == $units
            @if $counter == $columns
              $half-gutter: true
            @if $half-gutter
              @return $grid-return - ($calculated-gutter / 2)
            @return $grid-return - $calculated-gutter

@if type-of($name) == 'string' and (type-of($components) == 'list' or type-of($components) == 'color') and length($components) >= 1
        $color-base: null
        // only a single color is provided
        @if type-of($components) == 'color'
          $color-base: $components
        // a list of colors is provided
        @else if type-of($components) == 'list'
          $color-base: nth($components, 1)
        $color-invert: null
        // is an inverted color provided ?
        @if length($components) > 1
          $color-invert: nth($components, 2)
        // we only want a color as base color
        @if type-of($color-base) == 'color'
          // if inverted color is not provided or is not a color we compute it
          @if type-of($color-invert) != 'color'
            $color-invert: findColorInvert($color-base)
          // we merge this colors elements as map with bulma colors (we can override them this way, no multiple definition for the same name)
          $merged-colors: map_merge($merged-colors, ($name: ($color-base, $color-invert)))

@for $i from 1 through string.length($value)
    $char-str: string.slice($value, $i, $i)
    $char-num: -get-number-($char-str)
    // In case the char is not a number stop parse.
    @if not (meta.is-number($char-num) or $char-str == '.')
      // If result is number add unit and operator.
      @if meta.is-number($result)
        $unit: string.slice($value, $i)
        @if $negative
          $result: $result * -1
        @if unit.is($unit)
          $result: unit.add($result, $unit)
      @return $result

    @if $result == null
      $result: 0

    @if $char-str == '.'
      $divider: 1
    @else if $divider == 0
      $result: $result * 10 + $char-num
    @else
      $divider: $divider * 10
      $result: $result + math.div($char-num, $divider)

